// ==========================================
// 1. RECEBENDO AS VARIÁVEIS COM SEGURANÇA
// ==========================================
let stringListaPequena, stringListaGigante, rawTargetName;

// Testa o primeiro nó
try {
  // ATENÇÃO: Dependendo da versão do n8n, o valor retornado pelo Redis 
  // pode estar em 'value' ou 'data' em vez de 'propertyName'.
  stringListaPequena = $('PegarOpções').first().json.propertyName || $('PegarOpções').first().json.value;
} catch (error) {
  return [{ json: { erro: "🔴 O nó 'PegarOpções' não foi encontrado ou não executou. Verifique o nome exato (letras maiúsculas, acentos e espaços)!" } }];
}

// Testa o segundo nó
try {
  stringListaGigante = $('PegarLista').first().json.propertyName || $('PegarLista').first().json.value;
} catch (error) {
  return [{ json: { erro: "🔴 O nó 'PegarLista' não foi encontrado ou não executou. Verifique o nome exato!" } }];
}

// Testa o terceiro nó
try {
  rawTargetName = $('When Executed by Another Workflow').first().json.jogo
} catch (error) {
  return [{ json: { erro: "🔴 O nó 'Dados' não foi encontrado ou não executou. Verifique se o nome está certo e se o campo se chama 'Msg' mesmo." } }];
}

// ==========================================
// 2. CONVERSÃO DOS DADOS DO REDIS
// ==========================================
let listaPequenaAntiga = [];
let listaGigante = [];

try {
  listaPequenaAntiga = JSON.parse(stringListaPequena);
} catch (e) {
  return [{ json: { erro: "A lista pequena do Redis está vazia ou não é um JSON válido." } }];
}

try {
  listaGigante = JSON.parse(stringListaGigante);
} catch (e) {
  return [{ json: { erro: "A lista gigante do Redis está vazia ou não é um JSON válido." } }];
}

const limiteItens = listaPequenaAntiga.length || 5; 

// ==========================================
// FUNÇÃO DE NORMALIZAÇÃO
// ==========================================
function normalizarTexto(texto) {
  if (!texto) return "";
  return texto
    .toString()
    .normalize('NFD') 
    .replace(/[\u0300-\u036f]/g, "") 
    .toUpperCase() 
    .trim();
}

const targetName = normalizarTexto(rawTargetName);

// ==========================================
// 3. SUBTRAÇÃO (Remover os já vistos da lista gigante)
// ==========================================
const idsParaRemover = new Set(listaPequenaAntiga.map(jogo => jogo.id));
listaGigante = listaGigante.filter(jogo => !idsParaRemover.has(jogo.id));

// ==========================================
// 4. A BUSCA INTELIGENTE NOS JOGOS RESTANTES
// ==========================================
const matchesExatos = [];
const matchesPrioritarios = []; 
const matchesParciais = [];     

for (const game of listaGigante) {
  if (game && game.name && game.name.value) {
    const gameNameFromAPI = normalizarTexto(game.name.value);

    if (gameNameFromAPI === targetName) {
      matchesExatos.push(game);
    } 
    else if (
      gameNameFromAPI.includes(targetName + " ") || 
      gameNameFromAPI.includes(targetName + ":") ||
      gameNameFromAPI.includes(targetName + "-")
    ) {
      matchesPrioritarios.push(game);
    }
    else if (gameNameFromAPI.includes(targetName)) {
      matchesParciais.push(game);
    }
  }
}

// ==========================================
// FUNÇÃO DE ORDENAÇÃO POR ANO
// ==========================================
function ordenarPorAnoDecrescente(lista) {
  return lista.sort((a, b) => {
    const anoA = parseInt(a.yearpublished?.value) || 0;
    const anoB = parseInt(b.yearpublished?.value) || 0;
    return anoB - anoA; 
  });
}

ordenarPorAnoDecrescente(matchesExatos);
ordenarPorAnoDecrescente(matchesPrioritarios);
ordenarPorAnoDecrescente(matchesParciais);

// ==========================================
// 5. SELEÇÃO DA NOVA LISTA PEQUENA
// ==========================================
const todosMatches = [...matchesExatos, ...matchesPrioritarios, ...matchesParciais];
const novaListaPequena = todosMatches.slice(0, limiteItens);

// ==========================================
// 6. RETORNO FINAL
// ==========================================
return [{ 
  json: { 
    quantidade_novos_jogos: novaListaPequena.length,
    lista_pequena: novaListaPequena,
    lista_gigante: listaGigante
  } 
}];

// ==========================================
// 1. ONDE ESTÁ A LISTA PEQUENA?
// Substitua 'NomeDoSeuNo' pelo nome exato do nó onde a lista foi gerada ou lida do Redis
// ==========================================
let listaPequena;

try {
  // Se você está pegando direto do nó que gerou o JSON no passo anterior:
  listaPequena = $('Filtro').first().json.lista_pequena

  // IMPORTANTE: Se você estiver pegando a lista pequena de um nó GET do Redis, 
  // ela virá como texto. Nesse caso, apague a linha acima e use a linha abaixo:
  // listaPequena = JSON.parse($('NomeDoSeuNo').first().json.propertyName);

} catch (error) {
  return [{ json: { erro: "Nó não encontrado. Verifique o nome do nó no campo $('...')." } }];
}

// Verifica se a lista realmente tem dados
if (!listaPequena || !Array.isArray(listaPequena) || listaPequena.length === 0) {
  return [{ json: { prompt_jogos: "Nenhum jogo encontrado." } }];
}

// ==========================================
// 2. FORMATANDO O TEXTO PARA A IA (LLM)
// ==========================================
// Cria o cabeçalho do texto
let textoParaIA = "Novas Opções de jogos encontradas para jogo " + $('When Executed by Another Workflow').first().json.jogo + ":\n";

// Passa por cada jogo da lista e extrai só o nome e o ano
listaPequena.forEach((jogo, index) => {
  // Pega o nome e o ano, com uma trava de segurança caso a API não tenha enviado o ano
  const nomeJogo = jogo.name?.value || "Nome não informado";
  const anoJogo = jogo.yearpublished?.value || "Ano desconhecido";

  // Monta a linha no formato: "1. Nome do Jogo (Ano: 0000)"
  textoParaIA += `${index + 1}. ${nomeJogo} (Ano: ${anoJogo})\n`;
});

// ==========================================
// 3. RETORNO PARA O PRÓXIMO NÓ
// ==========================================
return [{ 
  json: { 
    // Retornamos o texto formatado limpo para jogar no Prompt do Agente
    prompt_jogos: textoParaIA 
  } 
}];
